package org.example.matrix.services;

import org.osgi.service.component.annotations.Component;
import org.osgi.service.component.annotations.Reference;
import org.osgi.service.component.annotations.Activate;
import org.osgi.service.component.annotations.Modified;
import org.osgi.service.metatype.annotations.Designate;

@Component(
    service = OracleService.class,
    immediate = true
)
@Designate(ocd = OracleConfiguration.class)
public class OracleServiceImpl implements OracleService {

    @Reference
    private MatrixNavigator navigator;

    private String prophecy;

    @Activate
    @Modified
    protected void activate(OracleConfiguration config) {
        this.prophecy = config.prophecy();
    }

    @Override
    public String getProphecy() {
        return "I can only show you the door. You're the one that has to walk through it.";
    }
}
